int mos6502_load_rom(CPUState *cpu, const char *filename, uint16_t address) {
    if (!cpu || !filename || !filename[0]) return -1;
    FILE *f = fopen(filename, "rb");
    if (!f) return -1;
    
    fseek(f, 0, SEEK_END);
    long size = ftell(f);
    fseek(f, 0, SEEK_SET);
    if (size < 0) {
        fclose(f);
        return -1;
    }
    
    if (address + size > cpu->memory_size) {
        fclose(f);
        return -1;
    }
    
    size_t read_len = fread(&cpu->memory[address], 1, (size_t)size, f);
    fclose(f);
    if (read_len != (size_t)size) return -1;
    snprintf(
        cpu->loaded_rom_debug,
        sizeof(cpu->loaded_rom_debug),
        "name=direct path=%s",
        filename
    );
    return 0;
}
int mos6502_load_system_roms(CPUState *cpu, const char *system_base_dir) {
    if (!cpu) return -1;
    (void)system_base_dir;
    cpu->loaded_rom_debug[0] = '\0';
    return 0;
}

int mos6502_load_cartridge_rom(CPUState *cpu, const char *path) {
    FILE *f;
    long file_size;
    uint8_t *buf;
    ComponentState_atari2600_cart0 *comp;
    size_t read_len;

    if (!cpu || !path || !path[0]) return -1;
    comp = &cpu->comp_atari2600_cart0;
    f = fopen(path, "rb");
    if (!f) return -1;
    if (fseek(f, 0, SEEK_END) != 0) { fclose(f); return -1; }
    file_size = ftell(f);
    if (file_size < 0) { fclose(f); return -1; }
    if (fseek(f, 0, SEEK_SET) != 0) { fclose(f); return -1; }
    buf = (uint8_t *)malloc((size_t)file_size);
    if (!buf) { fclose(f); return -1; }
    read_len = fread(buf, 1, (size_t)file_size, f);
    fclose(f);
    if (read_len != (size_t)file_size) { free(buf); return -1; }
    if (comp->rom_data != NULL) {
        free(comp->rom_data);
        comp->rom_data = NULL;
    }
    comp->rom_data = buf;
    comp->rom_size = (uint32_t)file_size;
    snprintf(
        cpu->loaded_rom_debug,
        sizeof(cpu->loaded_rom_debug),
        "name=atari2600_cart0 path=%s",
        path
    );
    return 0;
}


/* ===== Memory Access ===== */
uint8_t mos6502_read_byte(CPUState *cpu, uint16_t addr) {
    {
        ComponentState_atari2600_io *comp = &cpu->comp_atari2600_io;
        cpu->active_component_id = "atari2600_io";
        uint16_t a = (uint16_t)(addr & 0x1FFFu);
        if (a < 0x0080u) {
            /* TIA read registers mirror every 16 bytes across this range. */
            uint8_t r = (uint8_t)(a & 0x0Fu);
            switch (r) {
                case 0x00u: return comp->cxm0p;
                case 0x01u: return comp->cxm1p;
                case 0x02u: return comp->cxp0fb;
                case 0x03u: return comp->cxp1fb;
                case 0x04u: return comp->cxm0fb;
                case 0x05u: return comp->cxm1fb;
                case 0x06u: return comp->cxblpf;
                case 0x07u: return comp->cxppmm;
                case 0x08u: return comp->inpt0_latch;
                case 0x09u: return comp->inpt1_latch;
                case 0x0Au: return comp->inpt2_latch;
                case 0x0Bu: return comp->inpt3_latch;
                case 0x0Cu: {
                    return comp->inpt4_latch;
                }
                case 0x0Du: {
                    return comp->inpt5_latch;
                }
                default:
                    return 0x00u;
            }
        }
        if (a >= 0x0080u && a < 0x0200u) {
            return comp->riot_ram[(uint16_t)(a & 0x007Fu)];
        }
        if ((a & 0xFF80u) == 0x0280u) {
            uint8_t reg = (uint8_t)(a & 0x1Fu);
            uint8_t r = (uint8_t)(reg & 0x07u);
            if (r == 0x00u) {
                uint8_t joy0 = (uint8_t)cpu_component_call(cpu, "atari2600_io", "joy0_read", NULL, 0);
                uint8_t joy1 = (uint8_t)cpu_component_call(cpu, "atari2600_io", "joy1_read", NULL, 0);
                uint8_t in = 0xFFu;
                if ((joy0 & 0x01u) != 0u) in &= (uint8_t)~0x10u; /* up */
                if ((joy0 & 0x02u) != 0u) in &= (uint8_t)~0x20u; /* down */
                if ((joy0 & 0x04u) != 0u) in &= (uint8_t)~0x40u; /* left */
                if ((joy0 & 0x08u) != 0u) in &= (uint8_t)~0x80u; /* right */
                if ((joy1 & 0x01u) != 0u) in &= (uint8_t)~0x01u;
                if ((joy1 & 0x02u) != 0u) in &= (uint8_t)~0x02u;
                if ((joy1 & 0x04u) != 0u) in &= (uint8_t)~0x04u;
                if ((joy1 & 0x08u) != 0u) in &= (uint8_t)~0x08u;
                return (uint8_t)((in & (uint8_t)~comp->riot_swacnt) | (comp->riot_swcha_out & comp->riot_swacnt));
            }
            if (r == 0x01u) {
                return comp->riot_swacnt;
            }
            if (r == 0x02u) {
                uint8_t in = (uint8_t)cpu_component_call(cpu, "atari2600_io", "console_read", NULL, 0);
                return (uint8_t)((in & (uint8_t)~comp->riot_swbcnt) | (comp->riot_swchb_out & comp->riot_swbcnt));
            }
            if (r == 0x03u) {
                return comp->riot_swbcnt;
            }
            if (r == 0x04u || r == 0x06u) {
                /* Reading INTIM acknowledges timer flag (PA7 flag unaffected). */
                comp->riot_instat = (uint8_t)(comp->riot_instat & 0x7Fu);
                return comp->riot_timer;
            }
            if (r == 0x05u || r == 0x07u) {
                uint8_t v = comp->riot_instat;
                /* Reading TIMINT/INSTAT acknowledges only PA7 edge flag. */
                comp->riot_instat = (uint8_t)(comp->riot_instat & 0xBFu);
                return v;
            }
        }
    }
    {
        ComponentState_atari2600_cart0 *comp = &cpu->comp_atari2600_cart0;
        cpu->active_component_id = "atari2600_cart0";
        if (comp->rom_data == NULL || comp->rom_size == 0u) return 0u;
        addr = (uint16_t)(addr & 0x1FFFu); /* 6507 has 13-bit address bus */
        if (addr < 0x1000u || addr > 0x1FFFu) return 0u;
        {
            uint32_t off = (uint32_t)(addr - 0x1000u);
            uint32_t size = comp->rom_size;
            if (size == 2048u) {
                off &= 0x07FFu;
            } else if (size == 4096u) {
                off &= 0x0FFFu;
            } else if (size == 8192u) {
                if (addr == 0x1FF8u) comp->bank_select = 0u;
                if (addr == 0x1FF9u) comp->bank_select = 1u;
                off = (uint32_t)(comp->bank_select ? 0x1000u : 0x0000u) + (off & 0x0FFFu);
            } else if (size != 0u) {
                off %= size;
            }
            return comp->rom_data[off];
        }
    }
    if (addr >= cpu->memory_size) {
        cpu->error_code = CPU_ERROR_INVALID_MEMORY;
        return 0xFF;
    }
    return cpu->memory[addr];
}

void mos6502_write_byte(CPUState *cpu, uint16_t addr, uint8_t value) {
    {
        ComponentState_atari2600_io *comp = &cpu->comp_atari2600_io;
        cpu->active_component_id = "atari2600_io";
        uint16_t a = (uint16_t)(addr & 0x1FFFu);
        if (a < 0x0080u) {
            uint8_t r = (uint8_t)(a & 0x3Fu);
            #define TIA_ENQUEUE(_reg,_val,_delay) do { \
                if (comp->pending_count < 128u) { \
                    comp->pending_reg[comp->pending_count] = (uint8_t)(_reg); \
                    comp->pending_val[comp->pending_count] = (uint8_t)(_val); \
                    comp->pending_delay[comp->pending_count] = (uint8_t)(_delay); \
                    comp->pending_count = (uint8_t)(comp->pending_count + 1u); \
                } \
            } while(0)
            switch (r) {
                case 0x00u: {
                    uint8_t new_vsync = (uint8_t)(value & 0x02u);
                    if (new_vsync != 0u && comp->vsync_last == 0u) {
                        /* VSYNC rising edge: enter sync. */
                        comp->vsync_rise_pending = 1u;
                    } else if (new_vsync == 0u && comp->vsync_last != 0u) {
                        /* VSYNC falling edge: end of frame. */
                        comp->vsync_emit_pending = 1u;
                    }
                    comp->vsync = value;
                    comp->vsync_last = new_vsync;
                    return;
                }
                case 0x01u: TIA_ENQUEUE(0x01u, value, 1u); return; /* VBLANK */
                case 0x02u: {
                    /* WSYNC: halt CPU until next scanline boundary (approximate). */
                    uint32_t cc = comp->color_clock;
                    uint32_t remain = (cc < 228u) ? (228u - cc) : 0u;
                    if (comp->wsync_overshoot_clocks != 0u) {
                        uint32_t trim = (uint32_t)comp->wsync_overshoot_clocks;
                        remain = (remain > trim) ? (remain - trim) : 0u;
                        comp->wsync_overshoot_clocks = 0u;
                    }
                    uint64_t stall_cycles = (remain + 2u) / 3u;
                    if (stall_cycles > 0u) {
                        cpu->total_cycles += stall_cycles;
                    }
                    if (stall_cycles > 0u) {
                        uint32_t covered = (uint32_t)(stall_cycles * 3u);
                        comp->wsync_overshoot_clocks = (uint8_t)(covered > remain ? (covered - remain) : 0u);
                        comp->wsync_extra_cycles += (uint32_t)stall_cycles;
                    } else {
                        comp->wsync_overshoot_clocks = 0u;
                    }
                    /* Stall is already accounted via wsync_extra_cycles.
                       Do not also add raw clocks, or WSYNC time is double-counted. */
                    return;
                }
                case 0x03u: {
                    /* RSYNC: reset horizontal sync counter. */
                    uint32_t rsx = (comp->color_clock > 68u) ? (comp->color_clock - 68u) : 0u;
                    if (rsx > 159u) rsx = 159u;
                    comp->rsync_blank_x = (uint8_t)rsx;
                    comp->rsync_pending = 1u;
                    comp->hctr_delta = (int32_t)(228u - 3u) - (int32_t)comp->color_clock;
                    comp->color_clock = 228u - 3u;
                    return;
                }
                case 0x04u: comp->nusiz0 = value; return;
                case 0x05u: comp->nusiz1 = value; return;
                case 0x06u: comp->colup0 = value; return;
                case 0x07u: comp->colup1 = value; return;
                case 0x08u: comp->colupf = value; return;
                case 0x09u: comp->colubk = value; return;
                case 0x0Au: comp->ctrlpf = value; return;
                case 0x0Bu: TIA_ENQUEUE(0x0Bu, value, 1u); return; /* REFP0 */
                case 0x0Cu: TIA_ENQUEUE(0x0Cu, value, 1u); return; /* REFP1 */
                case 0x0Du: TIA_ENQUEUE(0x0Du, value, 2u); return; /* PF0 */
                case 0x0Eu: TIA_ENQUEUE(0x0Eu, value, 2u); return; /* PF1 */
                case 0x0Fu: TIA_ENQUEUE(0x0Fu, value, 2u); return; /* PF2 */
                case 0x10u: {
                    /* RESPx strobes are observed by the TIA a little later than the
                       CPU-side memory hook sees them. Bias by one CPU cycle (3 color
                       clocks) so coarse positioning lines up with the render pipeline. */
                    uint32_t cc = (comp->color_clock + 3u) % 228u;
                    uint8_t in_blank = (uint8_t)(cc < ((comp->extended_hblank != 0u) ? 76u : 68u));
                    uint8_t resx = (in_blank != 0u) ? ((cc >= 73u) ? 158u : 159u) : 157u;
                    comp->p0_counter = resx;
                    int32_t x = (int32_t)cc - 68 - comp->hctr_delta;
                    if (cc < 68u && cc >= 65u) x = 1;
                    if (x < 0) x = 0;
                    comp->p0_x = x;
                    comp->p0_ctr = 0u;
                    comp->p0_active = 1u;
                    if (comp->p0_is_rendering != 0u && (comp->p0_render_counter + 5) < 4) {
                        comp->p0_render_counter = (int8_t)(-5 + (int)resx - 157);
                    }
                    return;
                }
                case 0x11u: {
                    uint32_t cc = (comp->color_clock + 3u) % 228u;
                    uint8_t in_blank = (uint8_t)(cc < ((comp->extended_hblank != 0u) ? 76u : 68u));
                    uint8_t resx = (in_blank != 0u) ? ((cc >= 73u) ? 158u : 159u) : 157u;
                    comp->p1_counter = resx;
                    int32_t x = (int32_t)cc - 68 - comp->hctr_delta;
                    if (cc < 68u && cc >= 65u) x = 1;
                    if (x < 0) x = 0;
                    comp->p1_x = x;
                    comp->p1_ctr = 0u;
                    comp->p1_active = 1u;
                    if (comp->p1_is_rendering != 0u && (comp->p1_render_counter + 5) < 4) {
                        comp->p1_render_counter = (int8_t)(-5 + (int)resx - 157);
                    }
                    return;
                }
                case 0x12u: {
                    uint32_t cc = (comp->color_clock + 3u) % 228u;
                    uint8_t in_blank = (uint8_t)(cc < ((comp->extended_hblank != 0u) ? 76u : 68u));
                    uint8_t resx = (in_blank != 0u) ? ((cc >= 73u) ? 158u : 159u) : 157u;
                    comp->m0_counter = resx;
                    int32_t x = (int32_t)cc - 68 - comp->hctr_delta;
                    if (cc < 68u && cc >= 65u) x = 1;
                    if (x < 0) x = 0;
                    comp->m0_x = x;
                    comp->m0_ctr = 0u;
                    comp->m0_active = 1u;
                    if (comp->m0_is_rendering != 0u) {
                        uint8_t msize_bits = (uint8_t)((comp->nusiz0 >> 4) & 0x03u);
                        int msize = (msize_bits == 0u) ? 1 : (msize_bits == 1u ? 2 : (msize_bits == 2u ? 4 : 8));
                        if (comp->m0_render_counter < 0) {
                            comp->m0_render_counter = (int8_t)(-4 + (int)resx - 157);
                        } else {
                            if (msize == 8) {
                                comp->m0_render_counter = (int8_t)((int)resx - 157 + ((comp->m0_render_counter >= 4) ? 4 : 0));
                            } else if (msize == 4) {
                                comp->m0_render_counter = (int8_t)((int)resx - 157);
                            } else if (msize == 2) {
                                if (comp->hstate == 0u) comp->m0_is_rendering = (uint8_t)(comp->m0_render_counter > 1);
                                else if (comp->m0_render_counter == 0) comp->m0_render_counter += 1;
                            } else {
                                if (comp->hstate == 0u) comp->m0_is_rendering = (uint8_t)(comp->m0_render_counter > 0);
                            }
                        }
                    }
                    return;
                } /* RESM0 */
                case 0x13u: {
                    uint32_t cc = (comp->color_clock + 3u) % 228u;
                    uint8_t in_blank = (uint8_t)(cc < ((comp->extended_hblank != 0u) ? 76u : 68u));
                    uint8_t resx = (in_blank != 0u) ? ((cc >= 73u) ? 158u : 159u) : 157u;
                    comp->m1_counter = resx;
                    int32_t x = (int32_t)cc - 68 - comp->hctr_delta;
                    if (cc < 68u && cc >= 65u) x = 1;
                    if (x < 0) x = 0;
                    comp->m1_x = x;
                    comp->m1_ctr = 0u;
                    comp->m1_active = 1u;
                    if (comp->m1_is_rendering != 0u) {
                        uint8_t msize_bits = (uint8_t)((comp->nusiz1 >> 4) & 0x03u);
                        int msize = (msize_bits == 0u) ? 1 : (msize_bits == 1u ? 2 : (msize_bits == 2u ? 4 : 8));
                        if (comp->m1_render_counter < 0) {
                            comp->m1_render_counter = (int8_t)(-4 + (int)resx - 157);
                        } else {
                            if (msize == 8) {
                                comp->m1_render_counter = (int8_t)((int)resx - 157 + ((comp->m1_render_counter >= 4) ? 4 : 0));
                            } else if (msize == 4) {
                                comp->m1_render_counter = (int8_t)((int)resx - 157);
                            } else if (msize == 2) {
                                if (comp->hstate == 0u) comp->m1_is_rendering = (uint8_t)(comp->m1_render_counter > 1);
                                else if (comp->m1_render_counter == 0) comp->m1_render_counter += 1;
                            } else {
                                if (comp->hstate == 0u) comp->m1_is_rendering = (uint8_t)(comp->m1_render_counter > 0);
                            }
                        }
                    }
                    return;
                } /* RESM1 */
                case 0x14u: {
                    uint32_t cc = (comp->color_clock + 3u) % 228u;
                    uint8_t in_blank = (uint8_t)(cc < ((comp->extended_hblank != 0u) ? 76u : 68u));
                    uint8_t resx = (in_blank != 0u) ? ((cc >= 73u) ? 158u : 159u) : 157u;
                    comp->bl_counter = resx;
                    int32_t x = (int32_t)cc - 68 - comp->hctr_delta;
                    if (cc < 68u && cc >= 65u) x = 1;
                    if (x < 0) x = 0;
                    comp->bl_x = x;
                    comp->bl_ctr = 0u;
                    comp->bl_active = 1u;
                    comp->bl_is_rendering = 1u;
                    comp->bl_render_counter = (int8_t)(-4 + (int)resx - 157);
                    return;
                } /* RESBL */
                case 0x15u: comp->audc0 = (uint8_t)(value & 0x0Fu); return; /* AUDC0 */
                case 0x16u: comp->audc1 = (uint8_t)(value & 0x0Fu); return; /* AUDC1 */
                case 0x17u: comp->audf0 = (uint8_t)(value & 0x1Fu); return; /* AUDF0 */
                case 0x18u: comp->audf1 = (uint8_t)(value & 0x1Fu); return; /* AUDF1 */
                case 0x19u: comp->audv0 = (uint8_t)(value & 0x0Fu); return; /* AUDV0 */
                case 0x1Au: comp->audv1 = (uint8_t)(value & 0x0Fu); return; /* AUDV1 */
                case 0x1Bu:
                    TIA_ENQUEUE(0x1Bu, value, 1u);        /* GRP0 */
                    TIA_ENQUEUE(0xF1u, 0u, comp->pl_swap_delay); /* shuffle P1 */
                    return;
                case 0x1Cu:
                    TIA_ENQUEUE(0x1Cu, value, 1u);        /* GRP1 */
                    TIA_ENQUEUE(0xF0u, 0u, comp->pl_swap_delay); /* shuffle P0 */
                    TIA_ENQUEUE(0xF2u, 0u, 1u);           /* shuffle BL */
                    return;
                case 0x1Du: TIA_ENQUEUE(0x1Du, value, 1u); return; /* ENAM0 */
                case 0x1Eu: TIA_ENQUEUE(0x1Eu, value, 1u); return; /* ENAM1 */
                case 0x1Fu: TIA_ENQUEUE(0x1Fu, value, 1u); return; /* ENABL */
                case 0x20u: TIA_ENQUEUE(0x20u, value, 2u); return; /* HMP0 */
                case 0x21u: TIA_ENQUEUE(0x21u, value, 2u); return; /* HMP1 */
                case 0x22u: TIA_ENQUEUE(0x22u, value, 2u); return; /* HMM0 */
                case 0x23u: TIA_ENQUEUE(0x23u, value, 2u); return; /* HMM1 */
                case 0x24u: TIA_ENQUEUE(0x24u, value, 2u); return; /* HMBL */
                case 0x25u: comp->vdelp0 = value; return;
                case 0x26u: comp->vdelp1 = value; return;
                case 0x27u: comp->vdelbl = value; return;
                case 0x28u: {
                    uint8_t prev = (uint8_t)(comp->resmp0 & 0x02u);
                    comp->resmp0 = value;
                    if (prev != (comp->resmp0 & 0x02u) && (comp->resmp0 & 0x02u) == 0u) {
                        uint8_t div = ((comp->nusiz0 & 0x07u) == 0x05u) ? 2u : (((comp->nusiz0 & 0x07u) == 0x07u) ? 4u : 1u);
                        uint8_t offset = (div == 1u) ? 5u : (div == 2u ? 8u : 12u);
                        comp->m0_counter = (uint8_t)((comp->p0_counter + 160u - offset) % 160u);
                    }
                    return;
                }
                case 0x29u: {
                    uint8_t prev = (uint8_t)(comp->resmp1 & 0x02u);
                    comp->resmp1 = value;
                    if (prev != (comp->resmp1 & 0x02u) && (comp->resmp1 & 0x02u) == 0u) {
                        uint8_t div = ((comp->nusiz1 & 0x07u) == 0x05u) ? 2u : (((comp->nusiz1 & 0x07u) == 0x07u) ? 4u : 1u);
                        uint8_t offset = (div == 1u) ? 5u : (div == 2u ? 8u : 12u);
                        comp->m1_counter = (uint8_t)((comp->p1_counter + 160u - offset) % 160u);
                    }
                    return;
                }
                case 0x2Au: TIA_ENQUEUE(0x2Au, value, 6u); return; /* HMOVE */
                case 0x2Bu: TIA_ENQUEUE(0x2Bu, value, 2u); return; /* HMCLR */
                case 0x2Cu: {
                    comp->cxm0p = 0u;
                    comp->cxm1p = 0u;
                    comp->cxp0fb = 0u;
                    comp->cxp1fb = 0u;
                    comp->cxm0fb = 0u;
                    comp->cxm1fb = 0u;
                    comp->cxblpf = 0u;
                    comp->cxppmm = 0u;
                    return;
                }
                default: return;
            }
            #undef TIA_ENQUEUE
        }
        if (a >= 0x0080u && a < 0x0200u) {
            comp->riot_ram[(uint16_t)(a & 0x007Fu)] = value;
            return;
        }
        if ((a & 0xFF80u) == 0x0280u) {
            uint8_t reg = (uint8_t)(a & 0x1Fu);
            if (reg == 0x00u || reg == 0x08u || reg == 0x10u || reg == 0x18u) { /* SWCHA out latch (+ mirrors) */
                comp->riot_swcha_out = value;
                return;
            }
            if (reg == 0x01u || reg == 0x09u || reg == 0x11u || reg == 0x19u) { /* SWACNT (DDRA) (+ mirrors) */
                comp->riot_swacnt = value;
                return;
            }
            if (reg == 0x02u || reg == 0x0Au || reg == 0x12u || reg == 0x1Au) { /* SWCHB out latch (+ mirrors) */
                comp->riot_swchb_out = value;
                return;
            }
            if (reg == 0x03u || reg == 0x0Bu || reg == 0x13u || reg == 0x1Bu) { /* SWBCNT (DDRB) (+ mirrors) */
                comp->riot_swbcnt = value;
                return;
            }
            if (reg == 0x14u) { /* TIM1T */
                comp->riot_timer = value;
                comp->riot_timer_interval = 1u;
                comp->riot_timer_div = 0u;
                comp->riot_timer_wrap_pending = 0u;
                comp->riot_instat = (uint8_t)(comp->riot_instat & 0x40u);
                return;
            }
            if (reg == 0x15u) { /* TIM8T */
                comp->riot_timer = value;
                comp->riot_timer_interval = 8u;
                comp->riot_timer_div = 0u;
                comp->riot_timer_wrap_pending = 0u;
                comp->riot_instat = (uint8_t)(comp->riot_instat & 0x40u);
                return;
            }
            if (reg == 0x16u) { /* TIM64T */
                comp->riot_timer = value;
                comp->riot_timer_interval = 64u;
                comp->riot_timer_div = 0u;
                comp->riot_timer_wrap_pending = 0u;
                comp->riot_instat = (uint8_t)(comp->riot_instat & 0x40u);
                return;
            }
            if (reg == 0x17u) { /* T1024T */
                comp->riot_timer = value;
                comp->riot_timer_interval = 1024u;
                comp->riot_timer_div = 0u;
                comp->riot_timer_wrap_pending = 0u;
                comp->riot_instat = (uint8_t)(comp->riot_instat & 0x40u);
                return;
            }
            if (reg == 0x1Cu) { /* TIM1T mirror */
                comp->riot_timer = value;
                comp->riot_timer_interval = 1u;
                comp->riot_timer_div = 0u;
                comp->riot_timer_wrap_pending = 0u;
                comp->riot_instat = (uint8_t)(comp->riot_instat & 0x40u);
                return;
            }
            if (reg == 0x1Du) { /* TIM8T mirror */
                comp->riot_timer = value;
                comp->riot_timer_interval = 8u;
                comp->riot_timer_div = 0u;
                comp->riot_timer_wrap_pending = 0u;
                comp->riot_instat = (uint8_t)(comp->riot_instat & 0x40u);
                return;
            }
            if (reg == 0x1Eu) { /* TIM64T mirror */
                comp->riot_timer = value;
                comp->riot_timer_interval = 64u;
                comp->riot_timer_div = 0u;
                comp->riot_timer_wrap_pending = 0u;
                comp->riot_instat = (uint8_t)(comp->riot_instat & 0x40u);
                return;
            }
            if (reg == 0x1Fu) { /* T1024T mirror */
                comp->riot_timer = value;
                comp->riot_timer_interval = 1024u;
                comp->riot_timer_div = 0u;
                comp->riot_timer_wrap_pending = 0u;
                comp->riot_instat = (uint8_t)(comp->riot_instat & 0x40u);
                return;
            }
            if (reg == 0x04u || reg == 0x0Cu) { /* PA7 edge control: negative */
                comp->riot_pa7_irq_enable = 1u;
                comp->riot_pa7_posedge = 0u;
                comp->riot_instat = (uint8_t)(comp->riot_instat & 0xBFu);
                return;
            }
            if (reg == 0x05u || reg == 0x0Du) { /* PA7 edge control: positive */
                comp->riot_pa7_irq_enable = 1u;
                comp->riot_pa7_posedge = 1u;
                comp->riot_instat = (uint8_t)(comp->riot_instat & 0xBFu);
                return;
            }
            if (reg == 0x06u || reg == 0x0Eu) { /* PA7 edge control: disable */
                comp->riot_pa7_irq_enable = 0u;
                comp->riot_instat = (uint8_t)(comp->riot_instat & 0xBFu);
                return;
            }
            if (reg == 0x07u || reg == 0x0Fu) { /* PA7 edge control: enable */
                comp->riot_pa7_irq_enable = 1u;
                comp->riot_instat = (uint8_t)(comp->riot_instat & 0xBFu);
                return;
            }
        }
    }
    {
        ComponentState_atari2600_cart0 *comp = &cpu->comp_atari2600_cart0;
        cpu->active_component_id = "atari2600_cart0";
        (void)value;
        /* ROM is read-only. */
        addr = (uint16_t)(addr & 0x1FFFu);
        if (addr < 0x1000u || addr > 0x1FFFu) return;
        if (comp->rom_size == 8192u) {
            if (addr == 0x1FF8u) comp->bank_select = 0u;
            if (addr == 0x1FF9u) comp->bank_select = 1u;
        }
        return;
    }
    if (addr >= cpu->memory_size) {
        cpu->error_code = CPU_ERROR_INVALID_MEMORY;
        return;
    }

    cpu->memory[addr] = value;
}

uint16_t mos6502_read_word(CPUState *cpu, uint16_t addr) {
    uint16_t lo = mos6502_read_byte(cpu, addr);
    uint16_t hi = mos6502_read_byte(cpu, (uint16_t)(addr + 1u));
    return (uint16_t)(lo | (hi << 8));
}

void mos6502_write_word(CPUState *cpu, uint16_t addr, uint16_t value) {
    mos6502_write_byte(cpu, addr, (uint8_t)(value & 0xFFu));
    mos6502_write_byte(cpu, (uint16_t)(addr + 1u), (uint8_t)((value >> 8) & 0xFFu));
}

/* ===== Port I/O ===== */
uint8_t mos6502_read_port(CPUState *cpu, uint16_t port) {


    uint8_t value = (port < cpu->port_size) ? cpu->port_memory[port] : 0xFF;


    return value;
}

void mos6502_write_port(CPUState *cpu, uint16_t port, uint8_t value) {


    if (port >= cpu->port_size) return;
    cpu->port_memory[port] = value;


}

/* ===== Interrupts ===== */
void mos6502_interrupt(CPUState *cpu, uint8_t vector) {
    cpu->interrupt_vector = vector;
    cpu->interrupt_pending = true;
    cpu_irq_trace(cpu, "request", vector, 0u);
}

void mos6502_set_irq(CPUState *cpu, bool enabled) {
    cpu->interrupts_enabled = enabled;
}
/* No public component runtime API */

/* ===== Debug ===== */
void mos6502_dump_registers(CPUState *cpu) {
    printf("PC: 0x%04X SP: 0x%04X Flags: 0x%02X\n", cpu->pc, cpu->sp, cpu->flags.raw);
    for (int i = 0; i < 5; i++) {
        printf("R%d: 0x%02X ", i, cpu->registers[i]);
    }
    printf("\n");
}

void mos6502_dump_memory(CPUState *cpu, uint16_t start, uint16_t length) {
    for (uint16_t i = 0; i < length; i++) {
        if (i % 16 == 0) printf("\n%04X: ", start + i);
        printf("%02X ", cpu->memory[start + i]);
    }
    printf("\n");
}

void mos6502_dump_stack(CPUState *cpu, int depth) {
    if (depth < 0) depth = 0;
    printf("Stack from SP=0x%04X (depth=%d):\n", cpu->sp, depth);
    for (int i = 0; i < depth; i++) {
        uint16_t addr = (uint16_t)(cpu->sp + (uint16_t)i);
        if (addr >= cpu->memory_size) break;
        printf("  [%04X] = %02X\n", addr, cpu->memory[addr]);
    }
}

void mos6502_set_breakpoint(CPUState *cpu, uint16_t address) {
    if (cpu->num_break_points < 16) {
        cpu->break_points[cpu->num_break_points++] = address;
    }
}

void mos6502_clear_breakpoint(CPUState *cpu, uint16_t address) {
    for (int i = 0; i < cpu->num_break_points; i++) {
        if (cpu->break_points[i] == address) {
            for (int j = i; j < cpu->num_break_points - 1; j++) {
                cpu->break_points[j] = cpu->break_points[j + 1];
            }
            cpu->num_break_points--;
            break;
        }
    }
}

void mos6502_list_breakpoints(CPUState *cpu) {
    printf("Breakpoints (%d):\n", cpu->num_break_points);
    for (int i = 0; i < cpu->num_break_points; i++) {
        printf("  %d: 0x%04X\n", i, cpu->break_points[i]);
    }
}

void mos6502_trace_enable(CPUState *cpu, bool enable) {
    cpu->tracing_enabled = enable;
}
